const searchResults = $json.items ?? [];

// Node do nicho
const nicheNode = $('loop-by-niche').first()?.json ?? {};
const nichoSlug = nicheNode.slug ?? null;
const nichoNome = nicheNode.nome ?? null;
const idioma    = nicheNode.idioma ?? null;

// Mapeia canais + thumbnails
const channels = searchResults
  .map((item) => {
    const snippet = item?.snippet ?? {};
    return {
      canal_id: snippet.channelId ?? null,
      nome_canal: snippet.channelTitle ?? null,
      descricao: snippet.description ?? null,
      thumbnails: snippet.thumbnails ?? null, // <-- aqui entra o objeto default/medium/high
    };
  })
  .filter((c) => !!c.canal_id);

// Dedup por canal_id
const unique = channels.filter(
  (ch, idx, arr) => arr.findIndex((c) => c.canal_id === ch.canal_id) === idx
);

// Contadores
const total_raw = searchResults.length;
const total_mapped = channels.length;
const total_unique = unique.length;
const removed_duplicates = total_mapped - total_unique;

return [
  {
    json: {
      has_channels: total_unique > 0,
      channels: unique,
      channel_ids_batch: unique.map((c) => c.canal_id).join(","),
      nicho_slug: nichoSlug,
      nicho_nome: nichoNome,
      idioma,

      // debug útil pra você entender pq "encolheu"
      debug: {
        total_raw,
        total_mapped,
        total_unique,
        removed_duplicates,
      },
    },
  },
];

const channelItems = $json.items ?? [];

// Esses campos devem vir no item atual (do node anterior)
const nichoSlug =
  $('loop-by-niche').first().json.slug ?? $json.nichoSlug ?? $json.nicho?.slug ?? null;

const nichoNome =
 $('loop-by-niche').first().json.nome ?? $json.nichoNome ?? $json.nicho?.nome ?? null;

const idiomaAlvo =
  $json.idioma ?? $json.idioma_alvo ?? $json.idiomaAlvo ?? 'pt-BR';

if (channelItems.length === 0) {
  return [{ json: { skip: true, nicho_slug: nichoSlug, nicho_nome: nichoNome, idioma_alvo: idiomaAlvo } }];
}

const processed = channelItems.map((ch) => {
  const stats = ch?.statistics ?? {};
  const snippet = ch?.snippet ?? {};
  const branding = ch?.brandingSettings?.channel ?? {};

  const inscritos = Number.parseInt(stats.subscriberCount, 10) || 0;
  const totalVideos = Number.parseInt(stats.videoCount, 10) || 0;
  const totalViews = Number.parseInt(stats.viewCount, 10) || 0;
  const viewsPorVideo = totalVideos > 0 ? Math.round(totalViews / totalVideos) : 0;

  const defaultLanguage = snippet.defaultLanguage || branding.defaultLanguage || '';
  const title = snippet.title || '';
  const desc = snippet.description || '';

  const canalId = ch?.id ?? snippet?.channelId ?? null;

  return {
    json: {
      canal_id: canalId,
      nome_canal: title,
      descricao: desc,
      url_canal: canalId ? `https://youtube.com/channel/${canalId}` : null,
      inscritos,
      total_videos: totalVideos,
      total_views: totalViews,
      views_por_video: viewsPorVideo,
      pais: snippet.country || 'unknown',
      default_language: defaultLanguage,
      idioma_alvo: idiomaAlvo,
      nicho_slug: nichoSlug,
      nicho_nome: nichoNome,
    },
  };
});

// Sort por inscritos desc
processed.sort((a, b) => (b.json.inscritos || 0) - (a.json.inscritos || 0));

return processed;

