=Evaluate this channel for the niche "{{ $('process-channel-metrics').item.json.nicho_nome }}".

Channel data:
- Name: {{ $json.nome_canal }}
- Description: {{ $json.descricao }}
- Subscribers: {{ $json.inscritos }}
