const canalData = $('loop-by-channel').item.json;
const aiRaw = $input.first().json;

let score = 0.5;
let tomDeVoz = 'informativo';

try {
  // Try multiple ways to extract AI response
  let text = '';
  if (typeof aiRaw === 'string') text = aiRaw;
  else if (aiRaw.text) text = aiRaw.text;
  else if (aiRaw.output) text = typeof aiRaw.output === 'string' ? aiRaw.output : JSON.stringify(aiRaw.output);
  else if (aiRaw.message?.content) text = aiRaw.message.content;
  else if (aiRaw.response) text = aiRaw.response;
  else if (aiRaw.content) text = typeof aiRaw.content === 'string' ? aiRaw.content : JSON.stringify(aiRaw.content);
  else text = JSON.stringify(aiRaw);

  // Clean markdown code blocks
  text = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();

  // Try to find JSON in the text
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    if (parsed.score !== undefined) {
      score = parseFloat(parsed.score);
      if (isNaN(score)) score = 0.5;
    }
    if (parsed.tom_de_voz) tomDeVoz = parsed.tom_de_voz;
  } else {
    // Try to find score pattern like "score": 0.85 or score: 0.85
    const scoreMatch = text.match(/["']?score["']?\s*[:=]\s*(\d+\.?\d*)/i);
    if (scoreMatch) {
      score = parseFloat(scoreMatch[1]);
      if (isNaN(score)) score = 0.5;
    }
  }
} catch (e) {
  // If AI fails completely, use heuristic based on size
  const subs = canalData.inscritos || 0;
  const vpv = canalData.views_por_video || 0;
  if (subs >= 500000 && vpv >= 10000) score = 0.85;
  else if (subs >= 100000 && vpv >= 5000) score = 0.78;
  else if (subs >= 50000 && vpv >= 2000) score = 0.72;
  else if (subs >= 10000) score = 0.65;
  else score = 0.4;
}

// Clamp score
score = Math.min(1, Math.max(0, score));

const sanitize = (str) => String(str || '').replace(/'/g, "''");

return [{
  json: {
    canal_id: canalData.canal_id,
    nome_canal: sanitize(canalData.nome_canal),
    url_canal: canalData.url_canal,
    nicho_slug: canalData.nicho_slug,
    inscritos: canalData.inscritos,
    views_por_video: canalData.views_por_video,
    score: Math.round(score * 100) / 100,
    tom_de_voz: sanitize(tomDeVoz),
    is_approved: score >= 0.7
  }
}];
